// Pre-computed sorted icon keys (longest first for best substring match)
const ICON_KEYS = Object.keys(POI_ICON_SVGS).sort((a, b) => b.length - a.length);
const ALIAS_KEYS = Object.keys(CATEGORY_ALIASES).sort((a, b) => b.length - a.length);

/**
 * Levenshtein edit distance between two strings.
 */
function levenshtein(a: string, b: string): number {
  const m = a.length;
  const n = b.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] =
        a[i - 1] === b[j - 1]
          ? dp[i - 1][j - 1]
          : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
    }
  }
  return dp[m][n];
}

/**
 * Resolve a category string to a POI icon key using multi-level matching:
 *  1. Exact match — "restaurant" → "restaurant"
 *  2. Alias match — "gas station" → "fuel"
 *  3. Contains match — "Italian Restaurant" contains "restaurant" → match
 *  4. Word-level alias — "EV Charging Point" contains "ev charging" alias → "ev charger"
 *  5. Fuzzy match (Levenshtein) — "restraunt" ≈ "restaurant" → match (threshold: 30% of length, min 2)
 *
 * Returns the icon key or null if no match is found.
 */
export function resolveIconKey(category: string): string | null {
  const normalized = category.toLowerCase().trim();

  // 1. Direct exact match
  if (POI_ICON_SVGS[normalized]) return normalized;

  // 2. Alias exact match
  const alias = CATEGORY_ALIASES[normalized];
  if (alias && POI_ICON_SVGS[alias]) return alias;

  // 3. Contains match — check if any icon key is a substring of the category
  //    (longest key first to prefer "tourist attraction" over "park")
  for (const key of ICON_KEYS) {
    if (key === "generic") continue;
    if (normalized.includes(key)) return key;
  }

  // 4. Word-level alias — check if any alias key is a substring of the category
  for (const aliasKey of ALIAS_KEYS) {
    if (normalized.includes(aliasKey)) {
      const target = CATEGORY_ALIASES[aliasKey];
      if (target && POI_ICON_SVGS[target]) return target;
    }
  }

  // 5. Fuzzy match — Levenshtein distance with adaptive threshold
  //    Threshold: max(2, floor(length * 0.3)) — short words need near-exact, longer words get more tolerance
  let bestKey: string | null = null;
  let bestDist = Infinity;

  for (const key of ICON_KEYS) {
    if (key === "generic") continue;
    const threshold = Math.max(2, Math.floor(key.length * 0.3));
    const dist = levenshtein(normalized, key);
    if (dist <= threshold && dist < bestDist) {
      bestDist = dist;
      bestKey = key;
    }
  }

  // Also check fuzzy against alias keys
  for (const aliasKey of ALIAS_KEYS) {
    const threshold = Math.max(2, Math.floor(aliasKey.length * 0.3));
    const dist = levenshtein(normalized, aliasKey);
    if (dist <= threshold && dist < bestDist) {
      const target = CATEGORY_ALIASES[aliasKey];
      if (target && POI_ICON_SVGS[target]) {
        bestDist = dist;
        bestKey = target;
      }
    }
  }

  return bestKey;
}

// ── SVG path extraction ────────────────────────────────────────────────────

export interface SvgPathData {
  d: string;
  fillRule: "nonzero" | "evenodd";
}

/**
 * Convert a circle element to an SVG arc path string.
 */
function circleToPath(cx: number, cy: number, r: number): string {
  return (
    `M ${cx - r} ${cy} ` +
    `A ${r} ${r} 0 1 0 ${cx + r} ${cy} ` +
    `A ${r} ${r} 0 1 0 ${cx - r} ${cy} Z`
  );
}

/**
 * Parse SVG content and extract renderable path data.
 * Handles <path> and <circle> elements.
 */
export function extractSvgPaths(svgContent: string): SvgPathData[] {
  const paths: SvgPathData[] = [];

  // Match <path .../> elements (self-closing)
  const pathRegex = /<path\s+([^>]*?)\s*\/>/g;
  let match;
  while ((match = pathRegex.exec(svgContent)) !== null) {
    const attrs = match[1];
    const dMatch = attrs.match(/d="([^"]*)"/);
    if (dMatch) {
      const fillRuleMatch = attrs.match(/fill-rule="([^"]*)"/);
      paths.push({
        d: dMatch[1],
        fillRule: fillRuleMatch?.[1] === "evenodd" ? "evenodd" : "nonzero",
      });
    }
  }

  // Match <circle .../> elements (e.g., Generic.svg)
  const circleRegex = /<circle\s+([^>]*?)\s*\/>/g;
  while ((match = circleRegex.exec(svgContent)) !== null) {
    const attrs = match[1];
    const cxMatch = attrs.match(/cx="([^"]*)"/);
    const cyMatch = attrs.match(/cy="([^"]*)"/);
    const rMatch = attrs.match(/r="([^"]*)"/);
    if (cxMatch && cyMatch && rMatch) {
      paths.push({
        d: circleToPath(parseFloat(cxMatch[1]), parseFloat(cyMatch[1]), parseFloat(rMatch[1])),
        fillRule: "nonzero",
      });
    }
  }

  return paths;
}
